import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { detectWorkspaces } from "./workspaces.js";
let tmpDir;
beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-workspaces-"));
});
afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
});
function write(relativePath, content) {
    const full = path.join(tmpDir, relativePath);
    fs.mkdirSync(path.dirname(full), { recursive: true });
    fs.writeFileSync(full, content);
}
function mkdir(relativePath) {
    fs.mkdirSync(path.join(tmpDir, relativePath), { recursive: true });
}
describe("detectWorkspaces", () => {
    it("returns [] when no workspace config exists", () => {
        expect(detectWorkspaces(tmpDir)).toEqual([]);
    });
    it("expands pnpm-workspace.yaml globs", () => {
        write("pnpm-workspace.yaml", `packages:\n  - 'apps/*'\n  - 'packages/*'\n`);
        mkdir("apps/api");
        mkdir("apps/web");
        mkdir("packages/core");
        mkdir("services/worker"); // not in globs — should not appear
        const ws = detectWorkspaces(tmpDir)
            .map((d) => path.relative(tmpDir, d))
            .sort();
        expect(ws).toEqual(["apps/api", "apps/web", "packages/core"]);
    });
    it("expands package.json#workspaces (array form)", () => {
        write("package.json", JSON.stringify({ name: "root", workspaces: ["apps/*"] }));
        mkdir("apps/api");
        mkdir("apps/web");
        const ws = detectWorkspaces(tmpDir)
            .map((d) => path.relative(tmpDir, d))
            .sort();
        expect(ws).toEqual(["apps/api", "apps/web"]);
    });
    it("expands package.json#workspaces (object form)", () => {
        write("package.json", JSON.stringify({
            name: "root",
            workspaces: { packages: ["apps/*"] },
        }));
        mkdir("apps/api");
        const ws = detectWorkspaces(tmpDir).map((d) => path.relative(tmpDir, d));
        expect(ws).toEqual(["apps/api"]);
    });
    it("expands uv workspace members", () => {
        write("pyproject.toml", `[project]\nname = "root"\n\n[tool.uv.workspace]\nmembers = ["apps/api", "services/worker"]\n`);
        mkdir("apps/api");
        mkdir("services/worker");
        const ws = detectWorkspaces(tmpDir)
            .map((d) => path.relative(tmpDir, d))
            .sort();
        expect(ws).toEqual(["apps/api", "services/worker"]);
    });
    it("parses go.work use(...) block", () => {
        write("go.work", `go 1.21\n\nuse (\n\t./apps/api\n\t./services/worker  // comment\n)\n`);
        mkdir("apps/api");
        mkdir("services/worker");
        const ws = detectWorkspaces(tmpDir)
            .map((d) => path.relative(tmpDir, d))
            .sort();
        expect(ws).toEqual(["apps/api", "services/worker"]);
    });
    it("dedupes workspaces across ecosystems", () => {
        write("pnpm-workspace.yaml", `packages:\n  - 'apps/*'\n`);
        write("package.json", JSON.stringify({ name: "root", workspaces: ["apps/*"] }));
        mkdir("apps/api");
        const ws = detectWorkspaces(tmpDir);
        expect(ws).toHaveLength(1);
    });
    it("skips node_modules and hidden dirs when expanding '*'", () => {
        write("pnpm-workspace.yaml", `packages:\n  - 'apps/*'\n`);
        mkdir("apps/api");
        mkdir("apps/.hidden");
        mkdir("apps/node_modules");
        const ws = detectWorkspaces(tmpDir).map((d) => path.relative(tmpDir, d));
        expect(ws).toEqual(["apps/api"]);
    });
    it("skips '**' patterns instead of silently matching nothing", () => {
        write("pnpm-workspace.yaml", `packages:\n  - 'apps/**/pkg'\n  - 'libs/*'\n`);
        mkdir("apps/a/pkg");
        mkdir("libs/util");
        const calls = [];
        const originalWarn = console.warn;
        console.warn = (...args) => {
            calls.push(args);
        };
        let ws;
        try {
            ws = detectWorkspaces(tmpDir).map((d) => path.relative(tmpDir, d));
        }
        finally {
            console.warn = originalWarn;
        }
        // The ** pattern is skipped; the * pattern still resolves normally.
        expect(ws).toEqual(["libs/util"]);
        const flattened = calls.flat().join(" ");
        expect(flattened).toContain('"**" globs are not supported');
    });
});
